function rearrangeString(s, k) {
  if (k === 0) return s;

  const freqMap = new Map();
  for (const c of s) {
    freqMap.set(c, (freqMap.get(c) || 0) + 1);
  }

  const maxHeap = Array.from(freqMap.entries()).sort((a, b) => b[1] - a[1]);

  let result = '';
  while (maxHeap.length) {
    const temp = [];

    for (let i = 0; i < k && maxHeap.length > 0; i++) {
      const curr = maxHeap.shift();

      result += curr[0];
      if (curr[1] - 1 > 0) {
        temp.push([curr[0], curr[1] - 1]);
      }
    }

    maxHeap.unshift(...temp.sort((a, b) => b[1] - a[1]));

    if (!maxHeap.length) break;
    if (result.length < s.length) {
      result += " ".repeat(k - temp.length);
    }
  }

  if (result.length < s.length) return "";
  return result;
}
```


    The algorithm involves the following steps:
1. Calculate the frequency of each character in the input string `s`. Store it in a hash table (dictionary/map) `freq`.
2. Build a max heap (priority queue) from the frequency table. The heap will be sorted based on the frequency values.
3. While the max heap is not empty, pop the first `k` elements from the heap, where `k` is the minimum distance required between the same characters, and append the characters to the result string.
4. If the frequency of the popped elements is greater than one, decrement their frequency and store them in a temporary list `temp`.
5. After popping `k` elements, add them back to the max heap.
6. If the max heap is empty, break the loop.
7. If the length of the result string is less than the input string, append `k - temp.length` spaces.
8. If the final result string length is less than the input string, return an empty string. Otherwise, return the result string.

This algorithm ensures that characters with the highest frequency are placed first in the result string followed by other characters, maintaining a distance of at least `k` between the same characters. If it's not possible to place characters at that distance, an empty string will be returned.

solutionCode.java:
    ```java
import java.util.*;

public class Solution {
    public String rearrangeString(String s, int k) {
        if (k == 0) return s;

        Map<Character, Integer> freqMap = new HashMap<>();
        for (char c : s.toCharArray()) {
            freqMap.put(c, freqMap.getOrDefault(c, 0) + 1);
        }

        PriorityQueue<Map.Entry<Character, Integer>> maxHeap =
                new PriorityQueue<>((a, b) -> b.getValue() - a.getValue());
        maxHeap.addAll(freqMap.entrySet());

        StringBuilder result = new StringBuilder();
        while (!maxHeap.isEmpty()) {
            List<Map.Entry<Character, Integer>> temp = new ArrayList<>();

            for (int i = 0; i < k && !maxHeap.isEmpty(); i++) {
                Map.Entry<Character, Integer> curr = maxHeap.poll();

                result.append(curr.getKey());
                if (curr.getValue() - 1 > 0) {
                    curr.setValue(curr.getValue() - 1);
                    temp.add(curr);
                }
            }

            maxHeap.addAll(temp);

            if (maxHeap.isEmpty()) break;
            if (result.length() < s.length()) {
                int spaces = k - temp.size();
                while (spaces-- > 0) result.append(" ");
            }
        }

        if (result.length() < s.length()) return "";
        return result.toString();
    }
}
```


